import { Slider } from '@tale-ui/react/slider';

export function VolumeSlider() {
  return (
    <Slider.Root defaultValue={50} minValue={0} maxValue={100}>
      <Slider.Header>
        <Slider.Label>Volume</Slider.Label>
        <Slider.Output />
      </Slider.Header>
      <Slider.Control>
        <Slider.Track>
          <Slider.Indicator />
          <Slider.Thumb />
        </Slider.Track>
      </Slider.Control>
    </Slider.Root>
  );
}
